/** The black atlas key for a species/back combo, or null if not generated. */
export function erBlackSpritePath(speciesId: number, back: boolean): string | null {
  const key = `${back ? "back/" : ""}${speciesId}`;
  return ER_BLACK_SPRITES.has(key) ? `black/${key}` : null;
}
